import { Component, inject, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { CartService } from '../../core/services/cart.service';
import { CartItem } from '../../core/models';
import { formatPrice } from '../../core/api';

@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './cart.component.html',
  styleUrl: './cart.component.css',
})
export class CartComponent {
  private readonly cartService = inject(CartService);
  readonly format = formatPrice;

  // Data contract: mock cart lines render the mockup standalone;
  // service_agent replaces this with a CartService.load() call.
  readonly items = signal<CartItem[]>([
    {
      id: 'ci1', productId: '1', quantity: 2,
      product: { id: '1', name: 'CLASS-J Time-Delay Fuse 30A', description: '600V industrial time-delay fuse.', priceCents: 1899, imageUrl: null, stockQty: 120 },
    },
    {
      id: 'ci2', productId: '6', quantity: 1,
      product: { id: '6', name: 'Midget Fuse 10A 500V (Pack of 10)', description: 'Fast-acting control-circuit fuses.', priceCents: 3200, imageUrl: null, stockQty: 200 },
    },
  ]);

  readonly loading = signal<boolean>(false);
  readonly subtotal = computed(() =>
    this.items().reduce((sum, i) => sum + i.product.priceCents * i.quantity, 0),
  );

  ngOnInit(): void {
    this.cartService.load().subscribe({
      next: (cart) => this.items.set(cart.items),
      error: () => {},
    });
  }

  changeQty(item: CartItem, quantity: number): void {
    if (quantity < 1) return;
    this.cartService.updateItem(item.id, quantity).subscribe({
      next: (cart) => this.items.set(cart.items),
      error: () => {
        // optimistic local update for the mockup
        this.items.update((list) =>
          list.map((i) => (i.id === item.id ? { ...i, quantity } : i)),
        );
      },
    });
  }

  remove(item: CartItem): void {
    this.cartService.removeItem(item.id).subscribe({
      next: (cart) => this.items.set(cart.items),
      error: () => {
        this.items.update((list) => list.filter((i) => i.id !== item.id));
      },
    });
  }
}
